    metaDescription: 'Mgahinga Gorilla National Park Uganda 2026: 33,7 km2, 3 Virunga-Vulkane bis 4.127 m, Gorilla Trekking, Goldmeerkatzen, 76+ Saeugetiere, 180+ Voegel, Batwa-Kultur. Permit 800 USD.',
    breadcrumbs: [{ label: 'Nationalparks', href: '/nationalparks-uganda' }, { label: 'Mgahinga' }],
